import{_ as p,o as r,c as t,j as e,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const b=JSON.parse('{"title":"伽利略非线性步枪","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/3.B级/伽利略非线性步枪.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/3.B级/伽利略非线性步枪.md"}'),l={name:"4.资源分区/7.物品与装备/2.武器/远程武器/3.B级/伽利略非线性步枪.md"};function s(d,a,i,_,c,h){return r(),t("div",null,[...a[0]||(a[0]=[e("h1",{id:"伽利略非线性步枪",tabindex:"-1"},[n("伽利略非线性步枪 "),e("a",{class:"header-anchor",href:"#伽利略非线性步枪","aria-label":'Permalink to "伽利略非线性步枪"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),o('<h1 id="伽利略非线性步枪-1" tabindex="-1">伽利略非线性步枪 <a class="header-anchor" href="#伽利略非线性步枪-1" aria-label="Permalink to &quot;伽利略非线性步枪&quot;">​</a></h1><p>Weapon/Anti-Vehicle Model 6 Grindell/Galilean Nonlinear Rifle (W/AV M6 G/GNR) / M6反载具武器/伽利略非线性步枪</p><p>本质：科技本质</p><p>它最初是作为永恒之枪计划的内容，是一种便携性定向能武器，发射固态激光，由米斯利亚军械库制造，是UNSC为数不多的定向能武器之一。</p><p>类型：定向能武器/镭射步枪</p><p>价格：B+2000</p><p>长度：118.6 厘米（46.7 英寸）</p><p>重量： 空枪：19.07 千克（42.0 磅） 全重：20.4 千克（45 磅）</p><p>力量需求：5/双手</p><p>武器伤害：19L</p><p>电池模块：BA-53635/PLMD电池单元</p><p>供弹系统：电池单元（5发/30秒）</p><p>高速：8（983,571,056 英尺/秒）</p><p>基础射程：200</p><p>这把武器可以发射一种强大的微秒级强能量脉冲，能够烧穿厚金属层压板、纳米复合材料或硬化钢，光束可以同时穿透沿线性轨道对齐的多个障碍物 / 目标 ；强大的穿透力甚至可以打掉九辆并排停放的疣猪号的保险杠（啊？）。伽利略非线性步枪具有【超级贯穿】 和【能量武器】特性。</p><p>在武器准备就绪时，激光二极管上的护罩会升起，使其暴露在外，平常则隐藏在护罩中，这种设计是为了在平时保护相对脆弱的光学组件免受磕碰和伤害。当扣动扳机时，红色瞄准激光会指向目标，并伴随着武器蓄力充能时发出的呜呜声。在激光发生器开炮前，它需要充能大约3秒钟。在它充能时，充能的声音会明显逐渐变大，直到激光发射。只要武器没有开火，就可以在不损耗电量的情况下中止开火；比如，目标移出视线或炮手需要移动的情况。</p><p>这件武器发射时需要蓄力充能，功率足足有1.21吉瓦的电容器在充能时相当危险，需要使用者的绝对专注，这使得开启充能和维持充能需要消耗一个移动动作。<br> 在充能完成后，人物可以正常攻击发射激光，人物可以以自由动作使得激光在正前方扇形区域横扫，但这并不意味着可以使用自由动作攻击，只是自由动作做出扫射动作，这视为该武器具有【8加骰】特性。于此同时横移的激光束将如同刀锋一般切断范围内的目标，造成等同于伤害数一半的【肢体妨碍】点数，人物在攻击时需rp出想要切断的部位。</p><p>BA-53635/PLMD电池单元 5分<br> 一块电池可以支持维持10轮射击，即累积30秒蓄能攻击状态。无限能源的BA-53635/PLMD电池单元则需要750分</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',20)])])}const m=p(l,[["render",s]]);export{b as __pageData,m as default};
